module model_compare_counter_core #(
    parameter integer COUNT_WIDTH = 8,
    parameter integer STEP_WIDTH  = 4
) (
    input  logic                    clk,
    input  logic                    rst_n,
    input  logic                    enable,
    input  logic                    clear,
    input  logic [STEP_WIDTH-1:0]   step,
    output logic [COUNT_WIDTH-1:0]  count,
    output logic                    wrapped,
    output logic                    valid
);

    // SSOT fsm.control states: RESET, CLEAR, UPDATE, IDLE
    localparam [1:0] RESET  = 2'd0,
                     CLEAR  = 2'd1,
                     UPDATE = 2'd2,
                     IDLE   = 2'd3;

    logic [1:0] state;
    logic [1:0] next_state;

    // Architectural state mirrors function_model state_variables.
    logic [COUNT_WIDTH-1:0] count_q;
    logic                   wrapped_q;
    logic                   valid_q;

    localparam integer SUM_W = COUNT_WIDTH + 1;
    logic [SUM_W-1:0] add_full;

    // Committed outputs for the accepted cycle (latency=1 contract).
    logic [COUNT_WIDTH-1:0] out_count;
    logic                   out_wrapped;
    logic                   out_valid;

    // Explicit control predicate for cycle_model.handshake_rules.clear_enable_priority.
    logic clear_enable_priority;

    assign clear_enable_priority = (clear == 1'b1) && (enable == 1'b1);

    // Carry-out detects overflow; low COUNT_WIDTH bits are modulo result.
    assign add_full = {1'b0, count_q} + {{(SUM_W-STEP_WIDTH){1'b0}}, step};

    // Next committed values from current sampled inputs/state.
    assign out_count   = (clear == 1'b1)  ? {COUNT_WIDTH{1'b0}} :
                         (enable == 1'b1) ? add_full[COUNT_WIDTH-1:0] : count_q;
    assign out_wrapped = (clear == 1'b1)  ? 1'b0 :
                         (enable == 1'b1) ? add_full[COUNT_WIDTH] : 1'b0;
    assign out_valid   = (clear == 1'b1)  ? 1'b0 :
                         (enable == 1'b1) ? 1'b1 : 1'b0;

    always @(*) begin
        next_state = state;
        case (state)
            RESET: begin
                if (rst_n == 1'b1) begin
                    next_state = IDLE;
                end else begin
                    next_state = RESET;
                end
            end

            IDLE: begin
                if (clear == 1'b1) begin
                    next_state = CLEAR;
                end else if (enable == 1'b1) begin
                    next_state = UPDATE;
                end else begin
                    next_state = IDLE;
                end
            end

            UPDATE: begin
                next_state = IDLE;
            end

            CLEAR: begin
                next_state = IDLE;
            end

            default: begin
                next_state = RESET;
            end
        endcase
    end

    // Latency-1 update: commit outputs/state on same accepting edge.
    always @(posedge clk or negedge rst_n) begin
        if (!rst_n) begin
            state     <= RESET;
            count_q   <= {COUNT_WIDTH{1'b0}};
            wrapped_q <= 1'b0;
            valid_q   <= 1'b0;
        end else begin
            state <= next_state;

            // clear has priority over enable for FM_CLEAR vs FM_UPDATE.
            if (clear_enable_priority || (clear == 1'b1)) begin
                count_q   <= {COUNT_WIDTH{1'b0}};
                wrapped_q <= 1'b0;
                valid_q   <= 1'b0;
            end else begin
                count_q   <= out_count;
                wrapped_q <= out_wrapped;
                valid_q   <= out_valid;
            end
        end
    end

    assign count   = count_q;
    assign wrapped = wrapped_q;
    assign valid   = valid_q;

endmodule

